import pandas as pd
import numpy as np
from tqdm import tqdm
import torch
from PIL import Image
from transformers import Qwen2VLForConditionalGeneration, AutoProcessor
import io
import re
import os
import json
import argparse
import sys

# This script is an experimental integration of the Compact VLM Filter,
# inspired by the work from https://github.com/daulettoibazar/Compact_VLM_Filter.
# It adapts the filtering logic to process datasets generated by the VQASynth pipeline.

def load_vqasynth_dataset(dataset_path, image_base_dir):
    """
    Loads a dataset in a common VQA format (e.g., JSONL).
    Assumes each line is a JSON object with 'image' (filename) and 'conversations' keys.
    The 'text' is constructed from the conversation.
    """
    processed_data = []
    try:
        with open(dataset_path, 'r') as f:
            for line in tqdm(f, desc="Loading VQASynth dataset"):
                item = json.loads(line)
                # VQASynth data often has a conversational format.
                # For this filter, we'll concatenate the conversation turns into a single text block.
                # This is a simplification to fit the caption-judging model.
                full_text = " ".join([turn['value'] for turn in item.get('conversations', []) if 'value' in turn])
                if not full_text:
                    continue
                
                # Construct the full image path
                image_path = os.path.join(image_base_dir, item["image"])

                if os.path.exists(image_path):
                    processed_data.append({
                        'image_path': image_path,
                        'text': full_text,
                        'original_data': item, # Keep original data for reconstruction
                    })
                else:
                    print(f"Warning: Image not found at {image_path}", file=sys.stderr)

    except Exception as e:
        print(f"Error loading your dataset from {dataset_path}: {e}", file=sys.stderr)

    print(f"Total processed examples: {len(processed_data)}")
    return processed_data


class Qwen2VLFilter:
    """Class to filter image-text pairs using the compact Qwen2-VL judge model."""
    
    def __init__(self, model_path="Dauka-transformers/Compact_VLM_filter", batch_size=32):
        self.batch_size = batch_size
        # The model outputs scores in the format "score: {s}", where s is an integer.
        self.score_pattern = re.compile(r'score:\s*\{(\d+)\}')
        
        print(f"Loading compact VLM judge model from {model_path}...")
        self.processor = AutoProcessor.from_pretrained(model_path, trust_remote_code=True)
        self.model = Qwen2VLForConditionalGeneration.from_pretrained(
            model_path,
            device_map="cuda",
            torch_dtype=torch.bfloat16,
        )
        self.model.eval() 
        print(f"Model loaded successfully!")
    
    def filter_dataset(self, data, score_threshold=4):
        """Filters the dataset in batches and returns high-quality items."""
        filtered_data = []
        
        for i in tqdm(range(0, len(data), self.batch_size), desc="Filtering with VLM Judge"):
            batch = data[i:i + self.batch_size]
            
            images = []
            texts = []
            original_items = []
            
            for item in batch:
                try:
                    image = Image.open(item['image_path']).convert('RGB')
                    images.append(image)
                    texts.append(item['text'])
                    original_items.append(item['original_data'])
                except Exception as e:
                    print(f"Error opening image {item['image_path']}: {e}", file=sys.stderr)

            if not images:
                continue

            # This prompt is based on the source repository's fine-tuning.
            messages = [
                [
                    {'type': 'image'},
                    {'type': 'text', 'value': f'Judge the quality of the provided caption for the image on a scale of 1 to 5. score: {{s}}.\nCaption: {text}'}
                ] for text in texts
            ]

            inputs = self.processor(
                conversations=messages,
                images=images,
                padding=True,
                return_tensors='pt'
            ).to(self.model.device)

            with torch.no_grad():
                gen_kwargs = {"max_new_tokens": 10, "do_sample": False}
                outputs = self.model.generate(**inputs, **gen_kwargs)

            responses = self.processor.batch_decode(outputs, skip_special_tokens=True)

            for idx, response in enumerate(responses):
                match = self.score_pattern.search(response)
                if match:
                    score = int(match.group(1))
                    if score >= score_threshold:
                        filtered_data.append(original_items[idx])
        
        return filtered_data

def main():
    parser = argparse.ArgumentParser(description="Filter VQASynth data using a compact VLM judge.")
    parser.add_argument("--dataset_path", type=str, required=True, help="Path to the input VQASynth dataset JSONL file.")
    parser.add_argument("--image_base_dir", type=str, required=True, help="Base directory where images are stored.")
    parser.add_argument("--output_path", type=str, required=True, help="Path to save the filtered dataset JSONL file.")
    parser.add_argument("--model_path", type=str, default="Dauka-transformers/Compact_VLM_filter", help="HuggingFace path to the VLM judge model.")
    parser.add_argument("--batch_size", type=int, default=16, help="Batch size for processing.")
    parser.add_argument("--score_threshold", type=int, default=4, help="Minimum score (1-5) to keep a sample.")
    args = parser.parse_args()

    print("Starting VLM filtering process...")
    # 1. Load data
    unfiltered_data = load_vqasynth_dataset(args.dataset_path, args.image_base_dir)
    
    if not unfiltered_data:
        print("No data loaded. Exiting.")
        return
        
    # 2. Initialize filter
    vlm_filter = Qwen2VLFilter(model_path=args.model_path, batch_size=args.batch_size)

    # 3. Filter data
    filtered_data = vlm_filter.filter_dataset(unfiltered_data, score_threshold=args.score_threshold)

    # 4. Save filtered data
    with open(args.output_path, 'w') as f:
        for item in filtered_data:
            f.write(json.dumps(item) + '\n')

    print(f"Filtering complete.")
    print(f"Original samples: {len(unfiltered_data)}")
    print(f"Filtered samples: {len(filtered_data)}")
    print(f"Filtered dataset saved to {args.output_path}")

if __name__ == "__main__":
    main()
